"use client";

import React from "react";
import Link from "next/link";
import { useParams } from "next/navigation";
import { NeumorphicCard } from "@/components/NeumorphicCard";
import { useTrip } from "@/features/trips/hooks";
import {
  MapPin,
  Calendar,
  DollarSign,
  Lightbulb,
  AlertTriangle,
  Loader2,
  Settings,
  ChevronRight,
} from "lucide-react";
import { FinanceWidget } from "@/features/finances/components/FinanceWidget";

interface MissingInfoCardProps {
  icon: React.ReactNode;
  title: string;
  description: string;
  ctaLabel: string;
  ctaHref: string;
  accentColor: string;
}

function MissingInfoCard({ icon, title, description, ctaLabel, ctaHref, accentColor }: MissingInfoCardProps) {
  return (
    <Link href={ctaHref}>
      <NeumorphicCard className="p-4 flex items-center gap-4 group hover:shadow-neumorphic-sm transition-all cursor-pointer">
        <div className={`w-11 h-11 rounded-xl flex items-center justify-center shrink-0 ${accentColor}`}>
          {icon}
        </div>
        <div className="flex-1 min-w-0">
          <h4 className="font-bold text-sm text-text-main">{title}</h4>
          <p className="text-xs text-gray-500 mt-0.5">{description}</p>
        </div>
        <div className="flex items-center gap-1 text-xs font-semibold text-primary shrink-0">
          <span>{ctaLabel}</span>
          <ChevronRight size={14} className="group-hover:translate-x-0.5 transition-transform" />
        </div>
      </NeumorphicCard>
    </Link>
  );
}

export default function TripHome() {
  const params = useParams<{ tripId: string }>();
  const { data: trip, isLoading } = useTrip(params.tripId);

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 gap-4">
        <Loader2 className="w-10 h-10 text-primary animate-spin" />
        <p className="text-gray-500 font-medium">Cargando viaje...</p>
      </div>
    );
  }

  if (!trip) {
    return (
      <div className="text-center py-20">
        <p className="text-gray-500">No se encontr├│ el viaje.</p>
      </div>
    );
  }

  const missingDestination = !trip.destination;
  const missingDates = !trip.startDate || !trip.endDate;
  const hasMissingFields = missingDestination || missingDates;

  const proposalsUrl = `/trips/${params.tripId}/proposals`;

  return (
    <div className="space-y-6">
      {/* Trip Header */}
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-2xl font-black text-text-main tracking-tight font-nunito">
            {trip.name}
          </h1>
          {trip.destination && (
            <div className="flex items-center gap-1 text-gray-500 mt-1">
              <MapPin size={14} />
              <span className="text-sm">{trip.destination}</span>
            </div>
          )}
        </div>
        <Link href={`/trips/${params.tripId}/settings`}>
          <button className="p-2 text-gray-400 hover:text-gray-600 hover:bg-black/5 rounded-xl transition-colors">
            <Settings size={20} />
          </button>
        </Link>
      </div>

      {/* Missing Info Alert Section */}
      {hasMissingFields && (
        <div className="space-y-3">
          <div className="flex items-center gap-2 text-amber-600">
            <AlertTriangle size={18} />
            <h3 className="font-bold text-sm">Informaci├│n por definir</h3>
          </div>
          <p className="text-xs text-gray-500 -mt-1 ml-6">
            Us├í propuestas y encuestas para que el grupo decida.
          </p>

          <div className="space-y-3">
            {missingDestination && (
              <MissingInfoCard
                icon={<MapPin size={20} className="text-white" />}
                title="┬┐A d├│nde vamos?"
                description="El destino a├║n no fue definido."
                ctaLabel="Crear encuesta"
                ctaHref={proposalsUrl}
                accentColor="bg-primary"
              />
            )}
            {missingDates && (
              <MissingInfoCard
                icon={<Calendar size={20} className="text-white" />}
                title="┬┐Cu├índo viajamos?"
                description="Las fechas del viaje no est├ín definidas."
                ctaLabel="Sugerir fechas"
                ctaHref={`/trips/${params.tripId}/settings`}
                accentColor="bg-secondary"
              />
            )}
          </div>
        </div>
      )}

      {/* Finance Widget */}
      <FinanceWidget tripId={params.tripId} />

      {/* Quick Actions / Dashboard Cards */}
      <div className="space-y-3">
        <h3 className="font-bold text-sm text-text-main">Accesos R├ípidos</h3>
        <div className="grid grid-cols-2 gap-3">
          <Link href={proposalsUrl}>
            <NeumorphicCard className="p-4 flex flex-col items-center gap-2 text-center hover:shadow-neumorphic-sm transition-all cursor-pointer h-full">
              <div className="w-10 h-10 rounded-xl bg-amber-100 flex items-center justify-center">
                <Lightbulb size={20} className="text-amber-600" />
              </div>
              <span className="text-xs font-semibold text-text-main">Propuestas</span>
              <span className="text-[10px] text-gray-400">Propuestas del grupo</span>
            </NeumorphicCard>
          </Link>
          <Link href={`/trips/${params.tripId}/logistics`}>
            <NeumorphicCard className="p-4 flex flex-col items-center gap-2 text-center hover:shadow-neumorphic-sm transition-all cursor-pointer h-full">
              <div className="w-10 h-10 rounded-xl bg-teal-100 flex items-center justify-center">
                <MapPin size={20} className="text-teal-600" />
              </div>
              <span className="text-xs font-semibold text-text-main">Itinerario</span>
              <span className="text-[10px] text-gray-400">Transporte y actividades</span>
            </NeumorphicCard>
          </Link>
        </div>
      </div>

      {/* Timeline Placeholder */}
      {!missingDates && (
        <div className="space-y-3">
          <h3 className="font-bold text-sm text-text-main">Timeline</h3>
          <NeumorphicCard className="p-6 flex flex-col items-center gap-2 text-center">
            <Calendar size={32} className="text-gray-300" />
            <p className="text-sm text-gray-500">
              Aqu├¡ aparecer├ín tus actividades confirmadas.
            </p>
          </NeumorphicCard>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { useTrip, useUpdateTrip, useDeleteTrip } from "@/features/trips/hooks";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { createTripSchema, CreateTripFormValues } from "@/features/trips/types";
import { NeumorphicCard } from "@/components/NeumorphicCard";
import { NeumorphicInput } from "@/components/NeumorphicInput";
import { NeumorphicButton } from "@/components/NeumorphicButton";
import { Timestamp } from "firebase/firestore";
import {
  MapPin,
  Calendar,
  Type,
  ChevronLeft,
  Save,
  Loader2
} from "lucide-react";

export default function TripSettings() {
  const { tripId } = useParams<{ tripId: string }>();
  const router = useRouter();
  const { data: trip, isLoading } = useTrip(tripId);
  const updateMutation = useUpdateTrip();
  const deleteMutation = useDeleteTrip();
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<CreateTripFormValues>({
    resolver: zodResolver(createTripSchema) as any,
  });

  useEffect(() => {
    if (trip) {
      reset({
        name: trip.name,
        destination: trip.destination || "",
        description: trip.description || "",
        startDate: trip.startDate ? trip.startDate.toDate().toISOString().split("T")[0] : undefined,
        endDate: trip.endDate ? trip.endDate.toDate().toISOString().split("T")[0] : undefined,
        currency: trip.currency || "USD",
      } as any);
    }
  }, [trip, reset]);

  const onSubmit = async (values: CreateTripFormValues) => {
    try {
      await updateMutation.mutateAsync({
        tripId,
        data: {
          name: values.name,
          destination: values.destination || null,
          description: values.description || null,
          currency: values.currency,
          startDate: values.startDate ? Timestamp.fromDate(values.startDate) : null,
          endDate: values.endDate ? Timestamp.fromDate(values.endDate) : null,
        }
      });
      // Small delay to allow Firestore to propagate
      setTimeout(() => {
        router.push(`/trips/${tripId}`);
      }, 500);
    } catch (error) {
      console.error("DEBUG - Update Error:", error);
    }
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 gap-4">
        <Loader2 className="w-10 h-10 text-primary animate-spin" />
        <p className="text-gray-500 font-medium">Cargando configuraci├│n...</p>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto space-y-8">
      <div className="flex items-center gap-4">
        <button
          onClick={() => router.back()}
          className="p-2 bg-white rounded-xl shadow-neumorphic-sm text-gray-400 hover:text-primary transition-all"
        >
          <ChevronLeft size={20} />
        </button>
        <h1 className="text-2xl font-black text-text-main tracking-tight font-nunito">
          Configuraci├│n del Viaje
        </h1>
      </div>

      <NeumorphicCard className="p-6">
        <form onSubmit={handleSubmit(onSubmit as any)} className="space-y-6">
          <div className="space-y-4">
            <NeumorphicInput
              label="Nombre del Viaje"
              leftIcon={<Type size={18} />}
              placeholder="Ej. Roadtrip Europa 2025"
              error={errors.name?.message}
              {...register("name")}
            />

            <NeumorphicInput
              label="Destino (Opcional)"
              leftIcon={<MapPin size={18} />}
              placeholder="┬┐A d├│nde van?"
              error={errors.destination?.message}
              {...register("destination")}
            />

            <div className="grid grid-cols-2 gap-4">
              <NeumorphicInput
                label="Fecha Inicio"
                type="date"
                leftIcon={<Calendar size={18} />}
                error={errors.startDate?.message}
                {...register("startDate" as any)}
              />
              <NeumorphicInput
                label="Fecha Fin"
                type="date"
                leftIcon={<Calendar size={18} />}
                error={errors.endDate?.message}
                {...register("endDate" as any)}
              />
            </div>

            <div className="grid grid-cols-1 gap-4">
              <NeumorphicInput
                label="Moneda Principal del Viaje"
                placeholder="USD"
                {...register("currency")}
              />
            </div>

            <div className="flex flex-col gap-1.5">
              <label className="text-xs font-bold text-gray-400 ml-1">Descripci├│n</label>
              <textarea
                className="w-full bg-gray-50 border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-primary/20 shadow-neumorphic-inset-sm transition-all min-h-[100px]"
                placeholder="Escribe algo sobre este viaje..."
                {...register("description")}
              />
            </div>
          </div>

          <div className="pt-4">
            <NeumorphicButton
              type="submit"
              variant="primary"
              className="w-full py-4 text-sm font-black tracking-wide"
              disabled={updateMutation.isPending}
            >
              <div className="flex items-center justify-center gap-2">
                {updateMutation.isPending ? (
                  <Loader2 size={20} className="animate-spin" />
                ) : (
                  <Save size={20} />
                )}
                <span>{updateMutation.isPending ? "GUARDANDO..." : "GUARDAR CAMBIOS"}</span>
              </div>
            </NeumorphicButton>
          </div>
        </form>
      </NeumorphicCard>

      {/* Delete Section */}
      <div className="mt-12 mb-8">
        <h3 className="text-red-500 font-bold mb-4 px-2">Zona de Peligro</h3>
        <NeumorphicCard className="p-6 border border-red-100">
          {!showConfirmDelete ? (
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
              <div>
                <p className="font-bold text-gray-700">Eliminar Viaje</p>
                <p className="text-sm text-gray-500">
                  Esta acci├│n no se puede deshacer. Todos los datos se perder├ín.
                </p>
              </div>
              <NeumorphicButton
                variant="danger"
                onClick={() => setShowConfirmDelete(true)}
              >
                Eliminar
              </NeumorphicButton>
            </div>
          ) : (
            <div className="flex flex-col gap-4">
              <p className="text-red-600 font-bold text-sm">
                ┬┐Est├ís completamente seguro de que quieres eliminar el viaje &quot;{trip?.name}&quot;?
              </p>
              <div className="flex items-center gap-3">
                <NeumorphicButton
                  variant="danger"
                  className="flex-1"
                  disabled={deleteMutation.isPending}
                  onClick={async () => {
                    await deleteMutation.mutateAsync(tripId);
                    router.push("/trips");
                  }}
                >
                  {deleteMutation.isPending ? <Loader2 size={20} className="animate-spin mx-auto" /> : "S├¡, eliminar para siempre"}
                </NeumorphicButton>
                <NeumorphicButton
                  variant="secondary"
                  className="flex-1"
                  disabled={deleteMutation.isPending}
                  onClick={() => setShowConfirmDelete(false)}
                >
                  Cancelar
                </NeumorphicButton>
              </div>
            </div>
          )}
        </NeumorphicCard>
      </div>
    </div>
  );
}

