import { 
  collection, 
  doc, 
  serverTimestamp, 
  runTransaction 
} from "firebase/firestore";
import { db } from "@/lib/firebase";
import { Participant } from "@/types/tripio";

export interface CreateTripDTO {
  name: string;
  destination?: string;
  description?: string;
  startDate?: Date;
  endDate?: Date;
  currency: string;
  userId: string;
}

export const createTrip = async (data: CreateTripDTO): Promise<string> => {
  return await runTransaction(db, async (transaction) => {
    const tripsRef = collection(db, "trips");
    const newTripRef = doc(tripsRef);
    
    const tripData = {
      name: data.name,
      destination: data.destination || null,
      description: data.description || null,
      startDate: data.startDate || null,
      endDate: data.endDate || null,
      status: "planning",
      currency: data.currency,
      coverImage: "https://images.unsplash.com/photo-1488646953014-85cb44e25828?q=80&w=800&auto=format&fit=crop",
      createdBy: data.userId,
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp(),
    };

    transaction.set(newTripRef, tripData);

    const participantRef = doc(db, "trips", newTripRef.id, "participants", data.userId);
    const participantData: Omit<Participant, "id"> = {
      uid: data.userId,
      role: "owner",
      budgetLimit: null,
      joinedAt: serverTimestamp() as any,
      invitedBy: "system",
    };

    transaction.set(participantRef, participantData);

    return newTripRef.id;
  });
};

"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { NeumorphicInput } from "@/components/NeumorphicInput";
import { NeumorphicButton } from "@/components/NeumorphicButton";
import { Modal } from "@/components/ui/dialog/Modal";
import { createTripSchema, CreateTripFormValues } from "../../types";
import { useCreateTrip } from "../../hooks";
import { MapPin, Type, Calendar, DollarSign } from "lucide-react";

interface CreateTripModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
}

export const CreateTripModal = ({ isOpen, onClose, userId }: CreateTripModalProps) => {
  const { mutate: createTrip, isPending } = useCreateTrip();
  
  const {
    register,
    handleSubmit,
    formState: { errors },
    reset,
  } = useForm<z.input<typeof createTripSchema>>({
    resolver: zodResolver(createTripSchema) as any,
    defaultValues: {
      currency: "USD",
    },
  });

  const onSubmit = (data: CreateTripFormValues) => {
    createTrip(
      { ...data, userId },
      {
        onSuccess: () => {
          reset();
          onClose();
        },
      }
    );
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Crear Nuevo Viaje">
      <form onSubmit={handleSubmit(onSubmit as any)} className="space-y-5 p-1">
        <NeumorphicInput
          label="Nombre del Viaje *"
          placeholder="Ej: Expedici├│n Patagonia"
          leftIcon={<Type size={18} />}
          error={errors.name?.message as string}
          {...register("name")}
        />

        <NeumorphicInput
          label="Destino"
          placeholder="Ej: Bariloche, Argentina (opcional)"
          leftIcon={<MapPin size={18} />}
          error={errors.destination?.message as string}
          {...register("destination")}
        />

        <div className="grid grid-cols-2 gap-4">
          <NeumorphicInput
            label="Fecha Inicio"
            type="date"
            leftIcon={<Calendar size={18} />}
            error={errors.startDate?.message as string}
            {...register("startDate" as any)}
          />
          <NeumorphicInput
            label="Fecha Fin"
            type="date"
            leftIcon={<Calendar size={18} />}
            error={errors.endDate?.message as string}
            {...register("endDate" as any)}
          />
        </div>

        <div className="grid grid-cols-1 gap-4">
          <div className="flex flex-col gap-2 w-full">
            <label className="font-display text-sm font-semibold ml-2 text-text-main">
              Moneda Principal del Viaje
            </label>
            <select
              {...register("currency")}
              className="bg-white rounded-tripio w-full px-4 py-3 shadow-neumorphic-inset focus:outline-none focus:ring-2 focus:ring-secondary transition-all text-text-main appearance-none"
            >
              <option value="USD">USD</option>
              <option value="EUR">EUR</option>
              <option value="ARS">ARS</option>
              <option value="BRL">BRL</option>
            </select>
          </div>
        </div>

        <div className="pt-4 flex gap-4">
          <NeumorphicButton
            type="button"
            variant="secondary"
            className="flex-1"
            onClick={onClose}
          >
            Cancelar
          </NeumorphicButton>
          <NeumorphicButton
            type="submit"
            variant="primary"
            className="flex-1"
            disabled={isPending}
          >
            {isPending ? "Creando..." : "Crear Viaje"}
          </NeumorphicButton>
        </div>
      </form>
    </Modal>
  );
};

